proof fn phi_1_u64_prefix_freedom_external_body(a: u64, b: u64)
    requires
        !a.view_equal(&b),
        a.ghost_serialize().len() <= b.ghost_serialize().len(),
    ensures
        a.ghost_serialize() != b.ghost_serialize().subrange(0, a.ghost_serialize().len() as int),
{
    a.lemma_serialization_is_not_a_prefix_of(&b);
}

proof fn phi_2_usize_serialize_injective_external_body(a: usize, b: usize)
    requires
        a.is_marshalable(),
        b.is_marshalable(),
        a.ghost_serialize() == b.ghost_serialize(),
    ensures
        a == b,
{
    a.lemma_serialize_injective(&b);
}

